import json
from pathlib import Path

import pytest

AC_UID = "dd56db1a432be07e"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
BA_FILE = REPO_ROOT / "agents" / "ba.md"
CTX_FILE = REPO_ROOT / "docs" / "dev" / "context-20260524-122910.json"

CHECKLIST_LINE = (
    '- [ ] test_writer_expected boolean emitted in context.json: '
    '(complexity_tier in {STANDARD, COMPLEX}) OR (risk_level == "high")'
)
SCHEMA_REQUIRED = [
    "test_writer_expected",
    "complexity_tier in {STANDARD, COMPLEX}",
    "risk_level",
]


def test_AC_03():
    """
    GIVEN: agents/ba.md is read AND docs/dev/context-20260524-122910.json is parsed
    WHEN:  Quality Standards checklist + JSON-context schema are inspected AND jq queries run against context JSON
    THEN:  agents/ba.md Quality Standards contains the exact checklist line; agents/ba.md JSON-context schema documents test_writer_expected as required boolean with formula; context.json top-level test_writer_expected is type=boolean AND value equals the formula evaluated on this context's complexity_tier and risk_level
    """
    assert BA_FILE.exists(), f"{BA_FILE} missing"
    assert CTX_FILE.exists(), f"{CTX_FILE} missing"

    ba_text = BA_FILE.read_text(encoding="utf-8")

    # Exact-match checklist line present
    assert CHECKLIST_LINE in ba_text, (
        "Quality Standards checklist line missing in agents/ba.md.\n"
        f"Expected line:\n{CHECKLIST_LINE!r}"
    )

    # Schema doc strings present
    for req in SCHEMA_REQUIRED:
        assert req in ba_text, f"agents/ba.md JSON-context schema missing token {req!r}"

    # Context JSON parsing
    ctx = json.loads(CTX_FILE.read_text(encoding="utf-8"))
    assert "test_writer_expected" in ctx, "context.json missing top-level test_writer_expected"
    val = ctx["test_writer_expected"]
    assert isinstance(val, bool), (
        f"test_writer_expected must be JSON boolean; got {type(val).__name__} value={val!r}"
    )

    # Computed formula vs actual
    tier = ctx.get("complexity_tier")
    risk = ctx.get("risk_level")
    expected = (tier in {"STANDARD", "COMPLEX"}) or (risk == "high")
    assert val == expected, (
        f"test_writer_expected={val} does not match formula. "
        f"complexity_tier={tier!r} risk_level={risk!r} -> expected={expected}"
    )
